/**
 * خدمة BYO-API
 * Bring Your Own API - إدارة مفاتيح API للمستخدم
 *
 * المبادئ:
 * 1. لا يتم تخزين مفاتيح API على السيرفر
 * 2. جميع المفاتيح تُخزن محلياً في IndexedDB (مشفرة)
 * 3. الاتصالات تتم مباشرة من المتصفح إلى مزود الخدمة
 */

import {
  encryptData,
  decryptData,
  arrayBufferToBase64,
  base64ToArrayBuffer,
  uint8ArrayToBase64,
  base64ToUint8Array,
} from "./core";
import { getKeyManager } from "./keyManager";

/**
 * إعدادات مزود API
 */
export interface APIProviderConfig {
  id: string;
  providerName: string;
  endpointUrl: string;
  apiKey: string;
  metadata?: Record<string, string>;
}

/**
 * إعدادات مزود API مشفرة
 */
interface EncryptedAPIConfig {
  id: string;
  providerName: string;
  endpointUrl: string;
  encryptedApiKey: string;
  iv: string;
  createdAt: number;
  metadata?: Record<string, string>;
}

function withMetadata<T extends Record<string, unknown>>(
  value: T,
  metadata?: Record<string, string>
): T & { metadata?: Record<string, string> } {
  return metadata ? { ...value, metadata } : value;
}

const DB_NAME = "the-copy-byo-api";
const DB_VERSION = 1;
const STORE_NAME = "api-configs";

/**
 * فتح قاعدة البيانات المحلية
 */
async function openDatabase(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: "id" });
      }
    };
  });
}

/**
 * حفظ إعدادات API (مشفرة)
 */
export async function saveAPIConfig(config: APIProviderConfig): Promise<void> {
  const keyManager = getKeyManager();
  const kek = keyManager.getKEK();

  if (!kek) {
    throw new Error(
      "لم يتم العثور على مفتاح التشفير. يرجى تسجيل الدخول أولاً."
    );
  }

  // بناء AAD فريد لهذا الإعداد
  const aad = new TextEncoder().encode(`api-config:${config.id}`);

  // تشفير مفتاح API
  const { ciphertext, iv } = await encryptData(config.apiKey, kek, aad);

  const encryptedConfig: EncryptedAPIConfig = withMetadata(
    {
      id: config.id,
      providerName: config.providerName,
      endpointUrl: config.endpointUrl,
      encryptedApiKey: arrayBufferToBase64(ciphertext),
      iv: uint8ArrayToBase64(iv),
      createdAt: Date.now(),
    },
    config.metadata
  );

  const db = await openDatabase();
  const transaction = db.transaction(STORE_NAME, "readwrite");
  const store = transaction.objectStore(STORE_NAME);
  await new Promise<void>((resolve, reject) => {
    const request = store.put(encryptedConfig);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

/**
 * جلب إعدادات API (وفك تشفيرها)
 */
export async function getAPIConfig(
  id: string
): Promise<APIProviderConfig | null> {
  const keyManager = getKeyManager();
  const kek = keyManager.getKEK();

  if (!kek) {
    throw new Error(
      "لم يتم العثور على مفتاح التشفير. يرجى تسجيل الدخول أولاً."
    );
  }

  const db = await openDatabase();
  const transaction = db.transaction(STORE_NAME, "readonly");
  const store = transaction.objectStore(STORE_NAME);

  const encryptedConfig = await new Promise<EncryptedAPIConfig | undefined>(
    (resolve, reject) => {
      const request = store.get(id);
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    }
  );

  if (!encryptedConfig) {
    return null;
  }

  // فك تشفير مفتاح API
  const aad = new TextEncoder().encode(`api-config:${id}`);
  const ciphertext = base64ToArrayBuffer(encryptedConfig.encryptedApiKey);
  const iv = base64ToUint8Array(encryptedConfig.iv);

  const apiKey = await decryptData({ ciphertext, iv }, kek, aad);

  return withMetadata(
    {
      id: encryptedConfig.id,
      providerName: encryptedConfig.providerName,
      endpointUrl: encryptedConfig.endpointUrl,
      apiKey,
    },
    encryptedConfig.metadata
  );
}

/**
 * حذف إعدادات API
 */
export async function deleteAPIConfig(id: string): Promise<void> {
  const db = await openDatabase();
  const transaction = db.transaction(STORE_NAME, "readwrite");
  const store = transaction.objectStore(STORE_NAME);

  await new Promise<void>((resolve, reject) => {
    const request = store.delete(id);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

/**
 * الحصول على قائمة بجميع إعدادات API (بدون مفاتيح)
 */
export async function listAPIConfigs(): Promise<
  Omit<APIProviderConfig, "apiKey">[]
> {
  const db = await openDatabase();
  const transaction = db.transaction(STORE_NAME, "readonly");
  const store = transaction.objectStore(STORE_NAME);

  const configs = await new Promise<EncryptedAPIConfig[]>((resolve, reject) => {
    const request = store.getAll();
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });

  return configs.map((config) =>
    withMetadata(
      {
        id: config.id,
        providerName: config.providerName,
        endpointUrl: config.endpointUrl,
      },
      config.metadata
    )
  );
}

/**
 * اختبار اتصال API
 */
export async function testAPIConnection(
  config: APIProviderConfig
): Promise<{ success: boolean; message: string }> {
  try {
    const response = await fetch(config.endpointUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${config.apiKey}`,
      },
      body: JSON.stringify({
        model: "test",
        messages: [{ role: "user", content: "test" }],
      }),
    });

    if (response.ok || response.status === 401) {
      // 401 يعني أن الاتصال نجح لكن المفتاح قد يكون خاطئ
      return {
        success: true,
        message: "تم الاتصال بنجاح",
      };
    }

    return {
      success: false,
      message: `فشل الاتصال: ${response.status}`,
    };
  } catch (error) {
    return {
      success: false,
      message: `خطأ في الاتصال: ${error instanceof Error ? error.message : "خطأ غير معروف"}`,
    };
  }
}

/**
 * مسح جميع إعدادات API
 */
export async function clearAllAPIConfigs(): Promise<void> {
  const db = await openDatabase();
  const transaction = db.transaction(STORE_NAME, "readwrite");
  const store = transaction.objectStore(STORE_NAME);

  await new Promise<void>((resolve, reject) => {
    const request = store.clear();
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

/**
 * مكتبة التشفير الأساسية (Crypto Core)
 * Zero-Knowledge Encryption Library
 *
 * المبادئ الأساسية:
 * 1. جميع عمليات التشفير تتم على جانب العميل
 * 2. لا يتم إرسال أي مفاتيح تشفير إلى السيرفر
 * 3. KEK مشتق من كلمة المرور ولا يغادر المتصفح
 * 4. DEK عشوائي لكل مستند ويُلف بواسطة KEK
 */

// نوع مساعد لتوافق Uint8Array مع Web Crypto API في TypeScript 5.7+
type CryptoBuffer = Uint8Array<ArrayBuffer>;

// ثوابت التشفير
export const CRYPTO_CONSTANTS = {
  // KDF (Key Derivation Function)
  KDF_ITERATIONS: 600000, // عدد دورات PBKDF2
  KDF_HASH: "SHA-256",
  KDF_KEY_LENGTH: 32, // 256 بت
  SALT_LENGTH: 16, // 128 بت

  // AES-GCM
  AES_KEY_LENGTH: 256,
  AES_IV_LENGTH: 12, // 96 بت (موصى به لـ GCM)
  AES_TAG_LENGTH: 128, // 128 بت

  // Key Wrapping
  WRAP_IV_LENGTH: 12,
} as const;

/**
 * معلمات التشفير
 */
export interface EncryptionParams {
  ciphertext: ArrayBuffer;
  iv: Uint8Array;
  authTag?: Uint8Array;
}

/**
 * حزمة المستند المشفر
 */
export interface EncryptedDocument {
  ciphertext: ArrayBuffer;
  iv: Uint8Array;
  wrappedDEK: ArrayBuffer;
  wrappedDEKiv: Uint8Array;
  version: number;
  aad: string; // Additional Authenticated Data
}

/**
 * معلمات AAD (Additional Authenticated Data)
 */
export interface AADParams {
  userId: string;
  docId: string;
  version: number;
}

/**
 * توليد ملح عشوائي
 */
export function generateSalt(): CryptoBuffer {
  return crypto.getRandomValues(new Uint8Array(CRYPTO_CONSTANTS.SALT_LENGTH));
}

/**
 * توليد IV عشوائي
 */
export function generateIV(): CryptoBuffer {
  return crypto.getRandomValues(new Uint8Array(CRYPTO_CONSTANTS.AES_IV_LENGTH));
}

/**
 * توليد DEK عشوائي
 */
export async function generateDEK(): Promise<CryptoKey> {
  return await crypto.subtle.generateKey(
    {
      name: "AES-GCM",
      length: CRYPTO_CONSTANTS.AES_KEY_LENGTH,
    },
    true, // extractable (قابل للاستخراج للتغليف)
    ["encrypt", "decrypt"]
  );
}

/**
 * اشتقاق KEK من كلمة المرور باستخدام PBKDF2
 */
export async function deriveKEK(
  password: string,
  salt: Uint8Array
): Promise<CryptoKey> {
  // تحويل كلمة المرور إلى مفتاح
  const encoder = new TextEncoder();
  const passwordBuffer = encoder.encode(password);

  const passwordKey = await crypto.subtle.importKey(
    "raw",
    passwordBuffer,
    "PBKDF2",
    false,
    ["deriveBits", "deriveKey"]
  );

  // اشتقاق KEK
  return await crypto.subtle.deriveKey(
    {
      name: "PBKDF2",
      salt: salt as CryptoBuffer,
      iterations: CRYPTO_CONSTANTS.KDF_ITERATIONS,
      hash: CRYPTO_CONSTANTS.KDF_HASH,
    },
    passwordKey,
    {
      name: "AES-GCM",
      length: CRYPTO_CONSTANTS.AES_KEY_LENGTH,
    },
    false, // non-extractable (لا يمكن استخراجه)
    ["wrapKey", "unwrapKey"]
  );
}

/**
 * اشتقاق authVerifier من كلمة المرور (للمصادقة فقط)
 */
export async function deriveAuthVerifier(
  password: string,
  salt: Uint8Array
): Promise<Uint8Array> {
  const encoder = new TextEncoder();
  const passwordBuffer = encoder.encode(password);

  const passwordKey = await crypto.subtle.importKey(
    "raw",
    passwordBuffer,
    "PBKDF2",
    false,
    ["deriveBits"]
  );

  const verifierBits = await crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      salt: salt as CryptoBuffer,
      iterations: CRYPTO_CONSTANTS.KDF_ITERATIONS,
      hash: CRYPTO_CONSTANTS.KDF_HASH,
    },
    passwordKey,
    256 // 256 بت
  );

  return new Uint8Array(verifierBits);
}

/**
 * بناء AAD من المعلمات
 */
export function buildAAD(params: AADParams): CryptoBuffer {
  const encoder = new TextEncoder();
  const aadString = `${params.userId}:${params.docId}:${params.version}`;
  return encoder.encode(aadString);
}

/**
 * تشفير البيانات باستخدام DEK
 */
export async function encryptData(
  data: string,
  dek: CryptoKey,
  aad: Uint8Array
): Promise<EncryptionParams> {
  const encoder = new TextEncoder();
  const dataBuffer = encoder.encode(data);
  const iv = generateIV();

  const ciphertext = await crypto.subtle.encrypt(
    {
      name: "AES-GCM",
      iv: iv,
      additionalData: aad as CryptoBuffer,
      tagLength: CRYPTO_CONSTANTS.AES_TAG_LENGTH,
    },
    dek,
    dataBuffer
  );

  return {
    ciphertext,
    iv,
  };
}

/**
 * فك تشفير البيانات باستخدام DEK
 */
export async function decryptData(
  params: EncryptionParams,
  dek: CryptoKey,
  aad: Uint8Array
): Promise<string> {
  const decrypted = await crypto.subtle.decrypt(
    {
      name: "AES-GCM",
      iv: params.iv as CryptoBuffer,
      additionalData: aad as CryptoBuffer,
      tagLength: CRYPTO_CONSTANTS.AES_TAG_LENGTH,
    },
    dek,
    params.ciphertext
  );

  const decoder = new TextDecoder();
  return decoder.decode(decrypted);
}

/**
 * تغليف DEK باستخدام KEK
 */
export async function wrapDEK(
  dek: CryptoKey,
  kek: CryptoKey
): Promise<{ wrappedKey: ArrayBuffer; iv: Uint8Array }> {
  const iv = generateIV();

  const wrappedKey = await crypto.subtle.wrapKey("raw", dek, kek, {
    name: "AES-GCM",
    iv: iv,
    tagLength: CRYPTO_CONSTANTS.AES_TAG_LENGTH,
  });

  return { wrappedKey, iv };
}

/**
 * فك تغليف DEK باستخدام KEK
 */
export async function unwrapDEK(
  wrappedKey: ArrayBuffer,
  iv: Uint8Array,
  kek: CryptoKey
): Promise<CryptoKey> {
  return await crypto.subtle.unwrapKey(
    "raw",
    wrappedKey,
    kek,
    {
      name: "AES-GCM",
      iv: iv as CryptoBuffer,
      tagLength: CRYPTO_CONSTANTS.AES_TAG_LENGTH,
    },
    {
      name: "AES-GCM",
      length: CRYPTO_CONSTANTS.AES_KEY_LENGTH,
    },
    true, // extractable (للتشفير/فك التشفير)
    ["encrypt", "decrypt"]
  );
}

/**
 * تشفير مستند كامل (عملية شاملة)
 */
export async function encryptDocument(
  content: string,
  kek: CryptoKey,
  aadParams: AADParams
): Promise<EncryptedDocument> {
  // 1. توليد DEK عشوائي
  const dek = await generateDEK();

  // 2. بناء AAD
  const aad = buildAAD(aadParams);

  // 3. تشفير المحتوى
  const { ciphertext, iv } = await encryptData(content, dek, aad);

  // 4. تغليف DEK
  const { wrappedKey: wrappedDEK, iv: wrappedDEKiv } = await wrapDEK(dek, kek);

  return {
    ciphertext,
    iv,
    wrappedDEK,
    wrappedDEKiv,
    version: aadParams.version,
    aad: `${aadParams.userId}:${aadParams.docId}:${aadParams.version}`,
  };
}

/**
 * فك تشفير مستند كامل (عملية شاملة)
 */
export async function decryptDocument(
  encryptedDoc: EncryptedDocument,
  kek: CryptoKey,
  aadParams: AADParams
): Promise<string> {
  // 1. فك تغليف DEK
  const dek = await unwrapDEK(
    encryptedDoc.wrappedDEK,
    encryptedDoc.wrappedDEKiv,
    kek
  );

  // 2. بناء AAD
  const aad = buildAAD(aadParams);

  // 3. فك تشفير المحتوى
  return await decryptData(
    {
      ciphertext: encryptedDoc.ciphertext,
      iv: encryptedDoc.iv,
    },
    dek,
    aad
  );
}

/**
 * توليد Recovery Key
 */
export function generateRecoveryKey(): string {
  const recoveryBytes = crypto.getRandomValues(new Uint8Array(32));
  return Array.from(recoveryBytes)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("")
    .match(/.{1,4}/g)!
    .join("-")
    .toUpperCase();
}

/**
 * تحويل ArrayBuffer إلى Base64
 */
export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer);
  let binary = "";
  for (let i = 0; i < bytes.length; i++) {
    binary += String.fromCharCode(bytes[i] ?? 0);
  }
  return btoa(binary);
}

/**
 * تحويل Base64 إلى ArrayBuffer
 */
export function base64ToArrayBuffer(base64: string): ArrayBuffer {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

/**
 * تحويل Uint8Array إلى Base64
 */
export function uint8ArrayToBase64(array: Uint8Array): string {
  return arrayBufferToBase64(array.buffer as ArrayBuffer);
}

/**
 * تحويل Base64 إلى Uint8Array
 */
export function base64ToUint8Array(base64: string): Uint8Array {
  return new Uint8Array(base64ToArrayBuffer(base64));
}

import { logger } from "@/lib/ai/utils/logger";

/**
 * Encrypted Document Service
 * خدمة المستندات المشفرة
 *
 * هذه الخدمة تدير حفظ وتحميل المستندات المشفرة
 */

import {
  encryptDocument,
  decryptDocument,
  getKeyManager,
  arrayBufferToBase64,
  base64ToArrayBuffer,
  uint8ArrayToBase64,
  base64ToUint8Array,
  type EncryptedDocument,
  type AADParams,
} from "@/lib/crypto";

export interface SaveDocumentParams {
  content: string;
  userId: string;
  docId?: string;
}

export interface LoadDocumentParams {
  docId: string;
  userId: string;
}

interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
}

interface SavedDocumentResponse {
  id?: string;
  version?: number;
}

interface EncryptedDocumentPayload {
  ciphertext: string;
  iv: string;
  wrappedDEK: string;
  wrappedDEKiv: string;
  version: number;
}

interface DocumentListEntry {
  id: string;
  version: number;
  ciphertextSize: number;
  createdAt: string;
  lastModified: string;
}

/**
 * حفظ مستند مشفر
 */
export async function saveEncryptedDocument(
  params: SaveDocumentParams
): Promise<{ success: boolean; docId?: string; error?: string }> {
  try {
    const keyManager = getKeyManager();
    const kek = keyManager.getKEK();

    if (!kek) {
      return {
        success: false,
        error: "لم يتم العثور على مفتاح التشفير. يرجى تسجيل الدخول أولاً.",
      };
    }

    // تحديد docId (جديد أو تحديث)
    const docId = params.docId ?? generateDocId();
    const version = params.docId ? await getNextVersion(params.docId) : 1;

    // تشفير المحتوى
    const aadParams: AADParams = {
      userId: params.userId,
      docId,
      version,
    };

    const encryptedDoc = await encryptDocument(params.content, kek, aadParams);

    // تحويل إلى Base64 للإرسال
    const payload = {
      ciphertext: arrayBufferToBase64(encryptedDoc.ciphertext),
      iv: uint8ArrayToBase64(encryptedDoc.iv),
      wrappedDEK: arrayBufferToBase64(encryptedDoc.wrappedDEK),
      wrappedDEKiv: uint8ArrayToBase64(encryptedDoc.wrappedDEKiv),
      version: encryptedDoc.version,
    };

    // إرسال إلى السيرفر
    const endpoint = params.docId ? `/api/docs/${params.docId}` : "/api/docs";
    const method = params.docId ? "PUT" : "POST";

    const response = await fetch(endpoint, {
      method,
      headers: {
        "Content-Type": "application/json",
      },
      credentials: "include",
      body: JSON.stringify(payload),
    });

    const data = (await response.json()) as ApiResponse<SavedDocumentResponse>;

    if (!data.success) {
      return {
        success: false,
        error: data.error ?? "فشل في حفظ المستند",
      };
    }

    return {
      success: true,
      docId: data.data?.id ?? docId,
    };
  } catch (error) {
    logger.error("خطأ في حفظ المستند المشفر:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "خطأ غير معروف",
    };
  }
}

/**
 * تحميل مستند مشفر
 */
export async function loadEncryptedDocument(
  params: LoadDocumentParams
): Promise<{ success: boolean; content?: string; error?: string }> {
  try {
    const keyManager = getKeyManager();
    const kek = keyManager.getKEK();

    if (!kek) {
      return {
        success: false,
        error: "لم يتم العثور على مفتاح التشفير. يرجى تسجيل الدخول أولاً.",
      };
    }

    // جلب المستند من السيرفر
    const response = await fetch(`/api/docs/${params.docId}`, {
      credentials: "include",
    });

    const data = (await response.json()) as ApiResponse<EncryptedDocumentPayload>;

    if (!data.success || !data.data) {
      return {
        success: false,
        error: data.error ?? "فشل في تحميل المستند",
      };
    }

    const encryptedDoc = data.data;

    // تحويل من Base64
    const docToDecrypt: EncryptedDocument = {
      ciphertext: base64ToArrayBuffer(encryptedDoc.ciphertext),
      iv: base64ToUint8Array(encryptedDoc.iv),
      wrappedDEK: base64ToArrayBuffer(encryptedDoc.wrappedDEK),
      wrappedDEKiv: base64ToUint8Array(encryptedDoc.wrappedDEKiv),
      version: encryptedDoc.version,
      aad: "", // سيتم بناؤه في decryptDocument
    };

    // فك التشفير
    const aadParams: AADParams = {
      userId: params.userId,
      docId: params.docId,
      version: encryptedDoc.version,
    };

    const content = await decryptDocument(docToDecrypt, kek, aadParams);

    return {
      success: true,
      content,
    };
  } catch (error) {
    logger.error("خطأ في تحميل المستند المشفر:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "خطأ غير معروف",
    };
  }
}

/**
 * قائمة المستندات
 */
export async function listEncryptedDocuments(): Promise<{
  success: boolean;
  documents?: {
    id: string;
    version: number;
    ciphertextSize: number;
    createdAt: string;
    lastModified: string;
  }[];
  error?: string;
}> {
  try {
    const response = await fetch("/api/docs", {
      credentials: "include",
    });

    const data = (await response.json()) as ApiResponse<DocumentListEntry[]>;

    if (!data.success) {
      return {
        success: false,
        error: data.error ?? "فشل في جلب قائمة المستندات",
      };
    }

    return {
      success: true,
      documents: data.data,
    };
  } catch (error) {
    logger.error("خطأ في جلب قائمة المستندات:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "خطأ غير معروف",
    };
  }
}

/**
 * حذف مستند
 */
export async function deleteEncryptedDocument(
  docId: string
): Promise<{ success: boolean; error?: string }> {
  try {
    const response = await fetch(`/api/docs/${docId}`, {
      method: "DELETE",
      credentials: "include",
    });

    const data = (await response.json()) as ApiResponse<unknown>;

    if (!data.success) {
      return {
        success: false,
        error: data.error ?? "فشل في حذف المستند",
      };
    }

    return { success: true };
  } catch (error) {
    logger.error("خطأ في حذف المستند:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "خطأ غير معروف",
    };
  }
}

/**
 * توليد معرف مستند
 */
function generateDocId(): string {
  return `doc_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

/**
 * الحصول على رقم الإصدار التالي
 */
async function getNextVersion(docId: string): Promise<number> {
  try {
    const response = await fetch(`/api/docs/${docId}`, {
      credentials: "include",
    });

    const data = (await response.json()) as ApiResponse<SavedDocumentResponse>;

    if (data.success && data.data?.version) {
      return data.data.version + 1;
    }

    return 1;
  } catch {
    return 1;
  }
}

/**
 * مدير المفاتيح المحلي
 * Key Manager for Zero-Knowledge Architecture
 *
 * يدير دورة حياة المفاتيح في الذاكرة و IndexedDB
 * لا يتم مزامنة أي مفاتيح مع السيرفر
 */

/**
 * مدير المفاتيح
 */
export class KeyManager {
  private static instance: KeyManager;
  private kek: CryptoKey | null = null;

  private constructor() {}

  /**
   * الحصول على المثيل الوحيد (Singleton)
   */
  public static getInstance(): KeyManager {
    if (!KeyManager.instance) {
      KeyManager.instance = new KeyManager();
    }
    return KeyManager.instance;
  }

  /**
   * تعيين KEK في الذاكرة
   */
  public setKEK(kek: CryptoKey): void {
    this.kek = kek;
  }

  /**
   * الحصول على KEK من الذاكرة
   */
  public getKEK(): CryptoKey | null {
    return this.kek;
  }

  /**
   * التحقق من وجود KEK
   */
  public hasKEK(): boolean {
    return this.kek !== null;
  }

  /**
   * مسح KEK من الذاكرة
   */
  public clearKEK(): void {
    this.kek = null;
  }

  /**
   * إنهاء الجلسة (مسح المفاتيح من الذاكرة)
   */
  public async endSession(): Promise<void> {
    this.clearKEK();
  }

  /**
   * حذف كامل (إنهاء الجلسة)
   */
  public async fullLogout(): Promise<void> {
    this.clearKEK();
  }
}

/**
 * الحصول على مدير المفاتيح
 */
export function getKeyManager(): KeyManager {
  return KeyManager.getInstance();
}
